// Parse AI output and flatten all sessions into individual items
const raw = $input.first().json.output || $input.first().json.text || '';

let schedule;
try {
  const cleaned = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
  schedule = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Could not parse study schedule JSON from AI. Raw: ' + raw.slice(0, 300));
}

if (!schedule.daily_plan || schedule.daily_plan.length === 0) {
  throw new Error('AI returned an empty daily plan. Check the exam date and subjects.');
}

// Flatten all sessions into individual items for SplitInBatches
const sessions = [];
for (const day of schedule.daily_plan) {
  for (const session of (day.sessions || [])) {
    sessions.push({
      // Session fields for Calendar + Sheets
      student_name: schedule.student_name,
      exam_date: schedule.exam_date,
      date: day.date,
      day_number: day.day_number,
      day_of_week: day.day_of_week,
      subject: session.subject,
      topic: session.topic,
      duration_hours: session.duration_hours,
      start_time: session.start_time,
      end_time: session.end_time,
      session_type: session.session_type,
      priority: session.priority,
      // Full schedule stored for reference after loop
      _overview_summary: schedule.overview_summary,
      _study_tips: JSON.stringify(schedule.study_tips || []),
      _total_sessions: schedule.total_sessions,
      _total_days: schedule.total_days,
      _subjects: JSON.stringify(schedule.subjects || []),
      _user_email: $('1. Form — Study Planner Input').item.json['Your Email'],
      _user_name: $('1. Form — Study Planner Input').item.json['Your Name']
    });
  }
}

if (sessions.length === 0) {
  throw new Error('No study sessions generated. The exam date may be too close or in the past.');
}

return sessions.map(s => ({ json: s }));

