// Build all session rows for Sheets and HTML email from stored data
// This runs ONCE after all calendar events are created (SplitInBatches done output)
// Get all sessions from node 3 parse output
const allSessions = $('3. Code — Parse Schedule').all();

if (!allSessions || allSessions.length === 0) {
  throw new Error('No session data found from parse node.');
}

// Get metadata from first session
const meta = allSessions[0].json;
const studentName = meta._user_name || '';
const userEmail = meta._user_email || '';
const examDate = meta.exam_date || '';
const overviewSummary = meta._overview_summary || '';
const studyTips = JSON.parse(meta._study_tips || '[]');
const subjects = JSON.parse(meta._subjects || '[]');
const totalSessions = meta._total_sessions || allSessions.length;
const totalDays = meta._total_days || 0;

// Build Sheets rows array
const sheetRows = allSessions.map(s => ({
  'Student Name': s.json.student_name,
  'Exam Date': s.json.exam_date,
  'Subject': s.json.subject,
  'Topic': s.json.topic,
  'Date': s.json.date,
  'Day': s.json.day_of_week + ' (Day ' + s.json.day_number + ')',
  'Start Time': s.json.start_time,
  'End Time': s.json.end_time,
  'Duration (hrs)': s.json.duration_hours,
  'Session Type': s.json.session_type,
  'Priority': s.json.priority,
  'Status': 'Scheduled'
}));

// Group sessions by date for HTML email
const byDate = {};
for (const s of allSessions) {
  const d = s.json.date;
  if (!byDate[d]) byDate[d] = { day_of_week: s.json.day_of_week, day_number: s.json.day_number, sessions: [] };
  byDate[d].sessions.push(s.json);
}

const esc = str => String(str || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

const sessionTypeColor = t => {
  if (t === 'New Learning') return '#3b82f6';
  if (t === 'Revision') return '#10b981';
  if (t === 'Practice Test') return '#f59e0b';
  if (t === 'Quick Review') return '#8b5cf6';
  return '#6b7280';
};

const priorityBadge = p => {
  const c = p === 'High' ? '#ef4444' : p === 'Medium' ? '#f97316' : '#22c55e';
  return `<span style="background:${c};color:#fff;font-size:10px;padding:2px 7px;border-radius:10px;font-weight:700;">${esc(p)}</span>`;
};

// Build schedule table rows grouped by day
let scheduleHtml = '';
for (const [date, dayData] of Object.entries(byDate)) {
  const dateFormatted = new Date(date).toLocaleDateString('en-US', { weekday:'long', month:'short', day:'numeric' });
  scheduleHtml += `
    <tr>
      <td colspan="5" style="background:#1e3a5f;color:#fff;padding:8px 12px;font-size:12px;font-weight:700;">
        Day ${dayData.day_number} — ${dateFormatted}
      </td>
    </tr>`;
  for (const session of dayData.sessions) {
    const tc = sessionTypeColor(session.session_type);
    scheduleHtml += `
    <tr style="border-bottom:1px solid #f0f4f8;">
      <td style="padding:7px 12px;font-size:13px;font-weight:600;color:#1e3a5f;">${esc(session.subject)}</td>
      <td style="padding:7px 12px;font-size:12px;color:#374151;">${esc(session.topic)}</td>
      <td style="padding:7px 12px;font-size:12px;color:#6b7280;">${esc(session.start_time)} – ${esc(session.end_time)}</td>
      <td style="padding:7px 12px;">
        <span style="background:${tc};color:#fff;font-size:10px;padding:2px 7px;border-radius:10px;font-weight:600;">${esc(session.session_type)}</span>
      </td>
      <td style="padding:7px 12px;">${priorityBadge(session.priority)}</td>
    </tr>`;
  }
}

const tipsHtml = studyTips.map(t => `<li style="margin-bottom:6px;font-size:13px;color:#374151;">${esc(t)}</li>`).join('');

const htmlEmail = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"></head>
<body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;background:#f0f4f8;padding:20px;">

  <div style="background:#1e3a5f;padding:28px;border-radius:10px 10px 0 0;">
    <div style="font-size:11px;color:#93c5fd;letter-spacing:1.5px;text-transform:uppercase;margin-bottom:8px;">Study Planner</div>
    <h1 style="color:#fff;font-size:22px;margin:0;">Your Study Schedule is Ready, ${esc(studentName)}!</h1>
    <p style="color:#93c5fd;font-size:13px;margin:8px 0 0;">Exam Date: ${esc(examDate)} &nbsp;•&nbsp; ${totalSessions} sessions across ${totalDays} days</p>
  </div>

  <div style="background:#fff;padding:24px;">
    <div style="background:#eff6ff;border-left:4px solid #3b82f6;padding:14px 16px;border-radius:0 6px 6px 0;margin-bottom:20px;">
      <p style="font-weight:700;color:#1e3a5f;margin:0 0 6px;">Study Plan Overview</p>
      <p style="font-size:13px;color:#374151;margin:0;line-height:1.7;">${esc(overviewSummary)}</p>
    </div>

    <p style="font-size:13px;color:#374151;margin-bottom:16px;">All study sessions have been added to your Google Calendar. Here is your complete schedule:</p>

    <table style="width:100%;border-collapse:collapse;font-size:13px;margin-bottom:24px;">
      <thead>
        <tr style="background:#f8fafc;">
          <th style="padding:8px 12px;text-align:left;font-size:11px;color:#6b7280;text-transform:uppercase;border-bottom:2px solid #e5e7eb;">Subject</th>
          <th style="padding:8px 12px;text-align:left;font-size:11px;color:#6b7280;text-transform:uppercase;border-bottom:2px solid #e5e7eb;">Topic</th>
          <th style="padding:8px 12px;text-align:left;font-size:11px;color:#6b7280;text-transform:uppercase;border-bottom:2px solid #e5e7eb;">Time</th>
          <th style="padding:8px 12px;text-align:left;font-size:11px;color:#6b7280;text-transform:uppercase;border-bottom:2px solid #e5e7eb;">Type</th>
          <th style="padding:8px 12px;text-align:left;font-size:11px;color:#6b7280;text-transform:uppercase;border-bottom:2px solid #e5e7eb;">Priority</th>
        </tr>
      </thead>
      <tbody>${scheduleHtml}</tbody>
    </table>

    <h3 style="color:#1e3a5f;font-size:14px;margin:0 0 10px;">Study Tips</h3>
    <ul style="padding-left:18px;margin:0 0 20px;">${tipsHtml}</ul>

    <div style="background:#f0fdf4;border-left:4px solid #10b981;padding:12px 16px;border-radius:0 6px 6px 0;font-size:13px;color:#065f46;">
      All ${totalSessions} study sessions are now in your Google Calendar. Open your calendar to view the full schedule.
    </div>
  </div>

  <div style="background:#1e3a5f;padding:14px 24px;border-radius:0 0 10px 10px;text-align:center;">
    <p style="color:#93c5fd;font-size:11px;margin:0;">Generated by n8n Daily Study Planner &nbsp;•&nbsp; Powered by GPT-4o-mini</p>
  </div>

</body>
</html>`;

return [{ json: {
  user_email: userEmail,
  student_name: studentName,
  exam_date: examDate,
  total_sessions: totalSessions,
  total_days: totalDays,
  sheet_rows: sheetRows,
  html_email: htmlEmail
}}];
